import React from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate(`/course/${course.id}`);
  };

  // ✅ FIXED: Saari values ab properly access ho rahi hain
  const getNotesCount = () => {
    return course.notes || course.note_count || course.total_notes || 0;
  };

  const getPyqsCount = () => {
    return course.pyqs || course.pyq_count || course.total_pyqs || 0;
  };

  const getLabCount = () => {
    return course.lab_manual || course.lab_count || course.lab_manuals || 0;
  };

  const getViews = () => {
    return course.views || course.total_views || course.view_count || 0;
  };

  const getDownloads = () => {
    return course.downloads || course.total_downloads || course.download_count || 0;
  };

  const getSyllabusStatus = () => {
    return course.syllabus || course.has_syllabus || course.syllabus_available || false;
  };

  // Course icon based on name
  const getCourseIcon = (name) => {
    const nameLower = name?.toLowerCase() || '';
    if (nameLower.includes('btech') || nameLower.includes('b.tech')) return '💻';
    if (nameLower.includes('bca')) return '📱';
    if (nameLower.includes('bba')) return '📊';
    if (nameLower.includes('mba')) return '🎓';
    if (nameLower.includes('mca')) return '💼';
    return '📚';
  };

  // Format course name
  const formatCourseName = (name) => {
    if (!name) return '';
    if (name.toLowerCase().includes('btech')) return 'B.Tech';
    if (name.toLowerCase().includes('bca')) return 'BCA';
    if (name.toLowerCase().includes('bba')) return 'BBA';
    if (name.toLowerCase().includes('mba')) return 'MBA';
    if (name.toLowerCase().includes('mca')) return 'MCA';
    return name;
  };

  // Format branch
  const formatBranch = (branch, courseName) => {
    if (!branch || branch === 'General' || branch === 'All') {
      if (courseName?.toLowerCase().includes('btech')) return 'Computer Science';
      if (courseName?.toLowerCase().includes('bca')) return 'Computer Applications';
      if (courseName?.toLowerCase().includes('bba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mca')) return 'Computer Applications';
    }
    return branch || 'General';
  };

  const notesCount = getNotesCount();
  const pyqsCount = getPyqsCount();
  const labCount = getLabCount();
  const views = getViews();
  const downloads = getDownloads();
  const hasSyllabus = getSyllabusStatus();

  // Styles
  const styles = {
    card: {
      background: 'white',
      borderRadius: '20px',
      padding: '1.8rem 1.5rem',
      boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      position: 'relative',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 20px 40px rgba(79, 70, 229, 0.2)',
        borderColor: '#4f46e5'
      }
    },
    iconWrapper: {
      background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
      width: '80px',
      height: '80px',
      borderRadius: '50%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      margin: '0 auto 1.2rem',
      boxShadow: '0 10px 20px rgba(79, 70, 229, 0.3)'
    },
    icon: {
      fontSize: '2.8rem',
      color: 'white'
    },
    title: {
      fontSize: '1.5rem',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '0.3rem',
      letterSpacing: '-0.5px'
    },
    branch: {
      color: '#6b7280',
      fontSize: '0.95rem',
      marginBottom: '1.5rem',
      paddingBottom: '1rem',
      borderBottom: '2px dashed #e5e7eb'
    },
    statsGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '1rem',
      marginBottom: '1rem'
    },
    statCard: {
      background: '#f8fafc',
      padding: '1rem 0.5rem',
      borderRadius: '16px',
      textAlign: 'center',
      border: '1px solid #e2e8f0',
      transition: 'all 0.2s'
    },
    statValue: {
      fontSize: '1.4rem',
      fontWeight: '800',
      color: '#4f46e5',
      marginBottom: '0.2rem',
      lineHeight: '1.2'
    },
    statLabel: {
      fontSize: '0.7rem',
      color: '#64748b',
      textTransform: 'uppercase',
      letterSpacing: '0.5px',
      fontWeight: '600'
    },
    syllabusCard: {
      gridColumn: 'span 2',
      background: hasSyllabus ? '#dcfce7' : '#fee2e2',
      padding: '0.8rem',
      borderRadius: '12px',
      color: hasSyllabus ? '#166534' : '#991b1b',
      fontSize: '0.9rem',
      fontWeight: '600',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '0.5rem',
      border: hasSyllabus ? '1px solid #86efac' : '1px solid #fecaca'
    },
    codeBadge: {
      position: 'absolute',
      top: '15px',
      right: '15px',
      background: '#dbeafe',
      color: '#1d4ed8',
      padding: '0.4rem 1rem',
      borderRadius: '20px',
      fontSize: '0.75rem',
      fontWeight: '700',
      border: '1px solid #93c5fd'
    },
    clickHint: {
      marginTop: '1.2rem',
      fontSize: '0.8rem',
      color: '#94a3b8',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '0.3rem',
      paddingTop: '1rem',
      borderTop: '2px dashed #e5e7eb'
    }
  };

  return (
    <div 
      style={styles.card} 
      onClick={handleClick}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-8px)';
        e.currentTarget.style.boxShadow = '0 25px 50px rgba(79, 70, 229, 0.25)';
        e.currentTarget.style.borderColor = '#4f46e5';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 10px 30px rgba(0, 0, 0, 0.1)';
        e.currentTarget.style.borderColor = '#e5e7eb';
      }}
    >
      {/* Course Code Badge */}
      {course.code && (
        <div style={styles.codeBadge}>
          {course.code}
        </div>
      )}

      {/* Icon */}
      <div style={styles.iconWrapper}>
        <span style={styles.icon}>{getCourseIcon(course.name)}</span>
      </div>

      {/* Title & Branch */}
      <h3 style={styles.title}>{formatCourseName(course.name)}</h3>
      <p style={styles.branch}>
        {formatBranch(course.branch, course.name)} • Sem {course.semester || 'All'}
      </p>

      {/* Stats Grid */}
      <div style={styles.statsGrid}>
        {/* Notes */}
        <div style={styles.statCard}>
          <div style={styles.statValue}>{notesCount}</div>
          <div style={styles.statLabel}>NOTES</div>
        </div>

        {/* PYQs */}
        <div style={styles.statCard}>
          <div style={styles.statValue}>{pyqsCount}</div>
          <div style={styles.statLabel}>PYQS</div>
        </div>

        {/* Labs (if available) */}
        {labCount > 0 && (
          <div style={styles.statCard}>
            <div style={styles.statValue}>{labCount}</div>
            <div style={styles.statLabel}>LABS</div>
          </div>
        )}

        {/* Views */}
        <div style={styles.statCard}>
          <div style={styles.statValue}>{views}</div>
          <div style={styles.statLabel}>VIEWS</div>
        </div>

        {/* Downloads */}
        <div style={styles.statCard}>
          <div style={styles.statValue}>{downloads}</div>
          <div style={styles.statLabel}>DOWNLOADS</div>
        </div>

        {/* Syllabus Status */}
        <div style={styles.syllabusCard}>
          <span>{hasSyllabus ? '✅' : '❌'}</span>
          <span>{hasSyllabus ? 'Syllabus Available' : 'No Syllabus'}</span>
        </div>
      </div>

      {/* Click Hint */}
      <div style={styles.clickHint}>
        <span style={{ fontSize: '1rem' }}>👆</span>
        <span>Click to view complete course details</span>
      </div>
    </div>
  );
};

export default CourseCard;
